import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { getDocs, deleteDoc } from "../../api/documentApi";

export default function DocumentList() {
  const [docs, setDocs] = useState([]);
  const [loading, setLoading] = useState(false);
  const [statusFilter, setStatusFilter] = useState("all");
  const navigate = useNavigate();

  const load = async () => {
    try {
      setLoading(true);
      const res = await getDocs();
      setDocs(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load documents");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const stats = useMemo(() => {
    const total = docs.length;
    const active = docs.filter((d) => d.status === "active").length;
    const archived = docs.filter((d) => d.status === "archived").length;
    const pending = docs.filter((d) => d.status === "pending").length;
    return { total, active, archived, pending };
  }, [docs]);

  const filtered = useMemo(() => {
    if (statusFilter === "all") return docs;
    return docs.filter((d) => d.status === statusFilter);
  }, [docs, statusFilter]);

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this document permanently?")) return;

    try {
      await deleteDoc(id);
      setDocs((prev) => prev.filter((d) => d._id !== id));
      alert("Document deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const getVehicleName = (v) => {
    if (!v) return "-";
    return `${v.brand || ""} ${v.type || ""}`.trim() || "-";
  };

  const getVehicleNumber = (v) => {
    if (!v) return "-";
    return v.vehicleNumber || v.vehicle_number || v.registrationNo || v.regNo || "-";
  };

  const getStatusBadge = (status) => {
    const statusMap = {
      active: "badgeSuccess",
      archived: "badgeInfo",
      pending: "badgeWarning",
    };
    return statusMap[status] || "badge";
  };

  return (
    <div className="page">
      {/* Page Header */}
      <div className="pageHead">
        <div>
          <div className="pageTitle">Physical Documents</div>
          <div className="pageSub">Manage and organize vehicle-related documents</div>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="kpiGrid">
        <div className="kpiCard">
          <div className="kpiLabel">Total Documents</div>
          <div className="kpiValue">{loading ? "—" : stats.total}</div>
          <div className="kpiSub">All records</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Active</div>
          <div className="kpiValue">{loading ? "—" : stats.active}</div>
          <div className="kpiSub">Currently active</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Archived</div>
          <div className="kpiValue">{loading ? "—" : stats.archived}</div>
          <div className="kpiSub">Archived docs</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Pending</div>
          <div className="kpiValue">{loading ? "—" : stats.pending}</div>
          <div className="kpiSub">Awaiting action</div>
        </div>
      </div>

      {/* Filter & Actions Card */}
      <div className="card cardPad" style={{ marginBottom: 14 }}>
        <div className="row" style={{ alignItems: "center", flexWrap: "wrap" }}>
          <div>
            <div className="sectionTitle">Document Management</div>
            <div className="sub">Filter and manage your document collection</div>
          </div>

          <div style={{ display: "flex", gap: 10, alignItems: "center", marginLeft: "auto", flexWrap: "wrap" }}>
            <select
              className="select"
              style={{ minWidth: 180 }}
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
            >
              <option value="all">All Status</option>
              <option value="active">Active</option>
              <option value="archived">Archived</option>
              <option value="pending">Pending</option>
            </select>

            <button className="btn btnPrimary" onClick={() => navigate("/documents/add")}>
              ➕ Add Document
            </button>
            <button 
              className="btn" 
              onClick={load} 
              disabled={loading}
              style={{ minWidth: 100 }}
            >
              {loading ? "Loading..." : "Refresh"}
            </button>
          </div>
        </div>
      </div>

      {/* Documents Table */}
      <div className="card cardPad">
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ borderBottom: "2px solid var(--border-light)" }}>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Type</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Vehicle</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Reg. Number</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Location</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Status</th>
              <th style={{ padding: "12px", textAlign: "right", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Actions</th>
            </tr>
          </thead>

          <tbody>
            {filtered.map((d) => (
              <tr key={d._id} style={{ borderBottom: "1px solid var(--border-light)", transition: "background 0.2s" }}>
                <td style={{ padding: "12px", fontWeight: "500", color: "var(--text)" }}>{d.docType || "—"}</td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>{getVehicleName(d.vehicle)}</td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>{getVehicleNumber(d.vehicle)}</td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>{d.location || "—"}</td>
                <td style={{ padding: "12px" }}>
                  <span className={`badge ${getStatusBadge(d.status)}`}>
                    {d.status || "—"}
                  </span>
                </td>
                <td style={{ padding: "12px", textAlign: "right" }}>
                  <button 
                    className="btn btnSmall" 
                    onClick={() => navigate(`/documents/edit/${d._id}`)}
                    style={{ marginRight: 6 }}
                  >
                    ✏️ Edit
                  </button>
                  <button
                    className="btn btnSmall"
                    onClick={() => handleDelete(d._id)}
                    style={{ background: "var(--danger)", color: "white" }}
                  >
                    🗑️ Delete
                  </button>
                </td>
              </tr>
            ))}

            {!loading && filtered.length === 0 && (
              <tr>
                <td colSpan="6" style={{ padding: "40px", textAlign: "center", color: "var(--text-secondary)" }}>
                  {statusFilter !== "all" ? "No documents found with this status" : "No documents yet"}
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
